package com.chaobo.scm.supplier.domain.quote;import com.chaobo.scm.common.error.BusinessException;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.junit.jupiter.api.Test;import java.math.*;import java.time.*;import java.util.*;import java.util.concurrent.atomic.*;import static org.assertj.core.api.Assertions.*;
class SupplierQuoteAggregateTest {private final Ids ids=new Ids();private SupplierQuoteAggregate quote(){return SupplierQuoteAggregate.create(1,10L,"RFQ-1","CNY",LocalDate.now(),LocalDate.now().plusDays(10),List.of(new QuoteLine(2,"SKU-1",BigDecimal.TEN,new BigDecimal("12.30"),new BigDecimal("13"),3,BigDecimal.ONE)),1,ids);}@Test void shouldSubmitConfirmAndAdopt(){var q=quote();q.submit(1,ids);q.confirm(2,ids);q.adopt("PA-1",2,ids);assertThat(q.status()).isEqualTo(QuoteStatus.ADOPTED);assertThat(q.pullEvents()).hasSize(4);}@Test void shouldModifyOnlyDraftAndRaiseEvent(){var q=quote();q.pullEvents();q.modifyDraft(LocalDate.now().plusDays(1),LocalDate.now().plusDays(20),List.of(new QuoteLine(2,"SKU-1",new BigDecimal("20"),new BigDecimal("11.50"),new BigDecimal("13"),2,BigDecimal.ONE)),1,ids);assertThat(q.validTo()).isEqualTo(LocalDate.now().plusDays(20));assertThat(q.lines().getFirst().unitPrice()).isEqualByComparingTo("11.50");assertThat(q.pullEvents()).extracting(e->e.eventType()).containsExactly("SupplierQuoteDraftModified");q.submit(1,ids);assertThatThrownBy(()->q.modifyDraft(LocalDate.now(),LocalDate.now().plusDays(2),q.lines(),1,ids)).isInstanceOf(BusinessException.class);}@Test void shouldNotAdoptBeforeConfirm(){var q=quote();assertThatThrownBy(()->q.adopt("PA-1",1,ids)).isInstanceOf(BusinessException.class);}@Test void shouldRejectSubmittedQuote(){var q=quote();q.submit(1,ids);q.reject("价格偏高",2,ids);assertThat(q.status()).isEqualTo(QuoteStatus.REJECTED);}private static final class Ids implements IdentifierGenerator{private final AtomicLong n=new AtomicLong(1);public long nextId(){return n.getAndIncrement();}public String nextBusinessNo(String p){return p+n.getAndIncrement();}}}
